      "supporting": "Travel to endemic area, acute onset of fever, malaise, petechiae, hypotension/shock, hemoconcentration/fluid extravasation (pleural effusions, ascites, mediastinal edema).",
      "against": "Severe biventricular dysfunction is less typical than simple plasma leakage, though myocarditis can occur.",
      "support_level": "Well-supported"
    },
    "Septic shock": {
      "supporting": "Hypotension, fever, tachycardia, elevated respiratory rate, potential for bacterial translocation due to chronic liver/portal hypertension.",
      "against": "Relatively rapid progression to severe biventricular failure despite fluid resuscitation.",
      "support_level": "Well-supported"
    },
    "Severe malaria": {
      "supporting": "Travel to Brazil (though less common than other regions), fever, shock, anemia, thrombocytopenia.",
      "against": "Negative rapid antigen test, though sensitivity can vary.",
      "support_level": "Weakly supported"
    },
    "Viral myocarditis": {
      "supporting": "ECG findings (ST/PR segment changes), acute biventricular failure, shock out of proportion to fluids.",
      "against": "Usually manifests with more specific cardiac symptoms, but often asymptomatic or masked by systemic illness.",
      "support_level": "Well-supported"
    },
    "Leptospirosis": {
      "supporting": "Exposure risk in Brazil, fever, myalgia, potential for multiorgan failure/myocarditis.",
      "against": "No mention of classic jaundice (Weil's disease), although not strictly required.",
      "support_level": "Weakly supported"
    },
    "Spontaneous bacterial peritonitis": {
      "supporting": "Known cirrhosis, ascites, fever, abdominal pain.",
      "against": "Doesn't explain the acute onset of systemic, rapid-onset cardiogenic/distributive shock.",
      "support_level": "Weakly supported"
    },
    "Hemophagocytic lymphohistiocytosis": {
      "supporting": "Fever, cytopenias, splenomegaly, multiorgan dysfunction.",
      "against": "Acute presentation more suggestive of an infectious trigger.",
      "support_level": "Weakly supported"
    }
  },
